#include <bits/stdc++.h>
using namespace std;
int d[4][2]={{-1,0},{0,-1},{1,0},{0,1}};
int n,m,p[26][2][2],sx,sy,ex,ey;
string s[302];
int dist[302][302];
void bfs(){
    queue<int> x,y;
    x.push(sx),y.push(sy),dist[sx][sy]=1;
    while(x.size()){
        int fx=x.front(),fy=y.front();
        x.pop(),y.pop();
        for(int i=0;i<4;i++){
            int xx=fx+d[i][0],yy=fy+d[i][1];
            //printf("%d %d\n",xx,yy);
            if(xx>0 && yy>0 && xx<=n && yy<=m && s[xx][yy]>='A' && s[xx][yy]<='Z'){
            	char tmp=s[xx][yy];
            	//printf("%d %d %d %d\n",p[s[xx][yy]-'A'][0][0],p[s[xx][yy]-'A'][0][1],p[s[xx][yy]-'A'][1][0],p[s[xx][yy]-'A'][1][1]);
                if(p[s[xx][yy]-'A'][0][0]==xx && p[s[xx][yy]-'A'][0][1]==yy)
                    xx=p[tmp-'A'][1][0],yy=p[tmp-'A'][1][1];
                else
                    xx=p[tmp-'A'][0][0],yy=p[tmp-'A'][0][1];
            }
            //printf("%d %d\n",xx,yy);
            if(xx>0 && yy>0 && xx<=n && yy<=m && s[xx][yy]!='#' && !dist[xx][yy]){
                dist[xx][yy]=dist[fx][fy]+1;
                x.push(xx),y.push(yy);
            }
        }
    }
}
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++){
        cin>>s[i];
        s[i]=" "+s[i];
        for(int j=1;j<=m;j++){
            if(s[i][j]=='@')
                sx=i,sy=j;
            else if(s[i][j]=='=')
                ex=i,ey=j;
            else if(s[i][j]>='A' && s[i][j]<='Z')
                if(!p[s[i][j]-'A'][0][0])
                    p[s[i][j]-'A'][0][0]=i,p[s[i][j]-'A'][0][1]=j;
                else
                    p[s[i][j]-'A'][1][0]=i,p[s[i][j]-'A'][1][1]=j;
        }
    }
    //printf("%d %d %d %d\n",sx,sy,ex,ey);
    //printf("%d %d %d %d\n",p['W'-'A'][0][0],p['W'-'A'][0][1],p['W'-'A'][1][0],p['W'-'A'][1][1]);
    bfs();
    /*for(int i=1;i<=n;i++){
    	for(int j=1;j<=m;j++)
    		printf("%d ",dist[i][j]);
    	printf("\n");
	}*/
    printf("%d",dist[ex][ey]-1);
    return 0;
}
